  private loadHighScores() {
    try {
      const data = localStorage.getItem('neon-sprint-scores');
      if (data) this.highScores = JSON.parse(data);
    } catch { /* ignore */ }
  }

  private saveHighScores() {
    try {
      localStorage.setItem('neon-sprint-scores', JSON.stringify(this.highScores));
    } catch { /* ignore */ }
  }

  private loadAchievements() {
    try {
      const data = localStorage.getItem('neon-sprint-achievements');
      if (data) {
        const saved = JSON.parse(data) as Record<string, boolean>;
        for (const a of this.achievements) {
          if (saved[a.id]) a.unlocked = true;
        }
      }
    } catch { /* ignore */ }
  }

  private saveAchievements() {
    try {
      const map: Record<string, boolean> = {};
      for (const a of this.achievements) {
        if (a.unlocked) map[a.id] = true;
      }
      localStorage.setItem('neon-sprint-achievements', JSON.stringify(map));
    } catch { /* ignore */ }
  }

  private unlockAchievement(id: string) {
    const a = this.achievements.find(x => x.id === id);
    if (a && !a.unlocked) {
      a.unlocked = true;
      this.saveAchievements();
      this.uiSystem?.showAchievementToast(a.name);
      this.audio?.playAchievement();
    }
  }

  private checkAchievements() {
    // Distance achievements
    const distChecks: [string, number][] = [
      ['distance-100', 100], ['distance-500', 500], ['distance-1000', 1000],
      ['distance-2500', 2500], ['distance-5000', 5000], ['distance-10000', 10000],
    ];
    for (const [id, target] of distChecks) {
      if (this.distance >= target) this.unlockAchievement(id);
    }

    // Score achievements
    const scoreChecks: [string, number][] = [
      ['score-1000', 1000], ['score-5000', 5000], ['score-10000', 10000],
      ['score-50000', 50000], ['score-100000', 100000],
    ];
    for (const [id, target] of scoreChecks) {
      if (this.score >= target) this.unlockAchievement(id);
    }

    // Orb achievements
    const orbChecks: [string, number][] = [
      ['orbs-10', 10], ['orbs-50', 50], ['orbs-100', 100], ['orbs-250', 250],
    ];
    for (const [id, target] of orbChecks) {
      if (this.totalOrbsThisRun >= target) this.unlockAchievement(id);
    }

    // Multiplier achievements
    const multChecks: [string, number][] = [
      ['multiplier-3', 3], ['multiplier-5', 5], ['multiplier-8', 8], ['multiplier-10', 10],
    ];
    for (const [id, target] of multChecks) {
      if (this.multiplier >= target) this.unlockAchievement(id);
    }

    // Speed achievements
    const speedChecks: [string, number][] = [
      ['speed-20', 20], ['speed-30', 30], ['speed-40', 40],
    ];
    for (const [id, target] of speedChecks) {
      if (this.speed >= target) this.unlockAchievement(id);
    }
    if (this.speed >= MAX_SPEED) this.unlockAchievement('speed-king');

    // Combo achievements
    const comboChecks: [string, number][] = [
      ['combo-10', 10], ['combo-25', 25], ['combo-50', 50],
    ];
    for (const [id, target] of comboChecks) {
      if (this.currentCombo >= target) this.unlockAchievement(id);
    }

    // Survival achievements
    const survChecks: [string, number][] = [
      ['survivor-60', 60], ['survivor-180', 180], ['survivor-300', 300],
    ];
    for (const [id, target] of survChecks) {
      if (this.elapsedTime >= target) this.unlockAchievement(id);
    }
  }

  private createPlayerVisual() {
    const mat = new MeshStandardMaterial({
      color: 0x003366,
      emissive: new Color(0x00ffff),
      emissiveIntensity: 2,
      transparent: true,
      opacity: 0.7,
    });
    const geo = new IcosahedronGeometry(0.25, 1);
    this.playerMesh = new Mesh(geo, mat);
    this.playerMesh.position.set(0, 0.5, -1.5);
    this.scene.add(this.playerMesh);

    const glowMat = new MeshBasicMaterial({
      color: 0x00ffff,
      transparent: true,
      opacity: 0.2,
      blending: AdditiveBlending,
    });
    this.playerGlow = new Mesh(new SphereGeometry(0.4, 16, 16), glowMat);
    this.playerGlow.position.copy(this.playerMesh.position);
    this.scene.add(this.playerGlow);
  }

  private hidePlayerVisual() {
    this.playerMesh.visible = false;
    this.playerGlow.visible = false;
  }

  private showPlayerVisual() {
    this.playerMesh.visible = true;
    this.playerGlow.visible = true;
  }

  private createSpeedLines() {
    const mat = new MeshBasicMaterial({
      color: 0x00aaff,
      transparent: true,
      opacity: 0,
      blending: AdditiveBlending,
    });
    for (let i = 0; i < 20; i++) {
      const geo = new BoxGeometry(0.02, 0.02, 2 + Math.random() * 3);
      const line = new Mesh(geo, mat.clone());
      line.position.set(
        (Math.random() - 0.5) * 6,
        Math.random() * 3 + 0.5,
        (Math.random() - 0.5) * 40 - 20,
      );
      line.visible = false;
      this.scene.add(line);
      this.speedLines.push(line);
    }
  }

  private updateSpeedLines(delta: number) {
    const speedFraction = (this.speed - BASE_SPEED) / (MAX_SPEED - BASE_SPEED);
    const opacity = Math.max(0, speedFraction - 0.3) * 0.5;
    const show = opacity > 0.01 && this.speedLinesEnabled;

    for (const line of this.speedLines) {
      line.visible = show;
      if (show) {
        (line.material as MeshBasicMaterial).opacity = opacity;
        line.position.z += this.speed * delta;
        if (line.position.z > DESPAWN_Z) {
          line.position.z = SPAWN_Z + Math.random() * 20;
          line.position.x = (Math.random() - 0.5) * 6;
          line.position.y = Math.random() * 3 + 0.5;
        }
      }
    }
  }

  private createObstaclePool() {
    for (let i = 0; i < 30; i++) {
      const colorIdx = i % OBSTACLE_COLORS.length;
      const factoryIdx = i % OBSTACLE_FACTORIES.length;
      const group = OBSTACLE_FACTORIES[factoryIdx](OBSTACLE_COLORS[colorIdx]);
      group.visible = false;
      this.scene.add(group);
      this.obstacles.push({ group, lane: 1, active: false, width: 1.6 });
    }
  }

  private createCollectiblePool() {
    for (let i = 0; i < 40; i++) {
      const colorIdx = i % COLLECTIBLE_COLORS.length;
      const mat = createCollectibleMaterial(COLLECTIBLE_COLORS[colorIdx]);
      const mesh = new Mesh(new SphereGeometry(0.2, 12, 12), mat);
      mesh.visible = false;
      this.scene.add(mesh);
      this.collectibles.push({
        mesh, lane: 1, active: false, pulsePhase: Math.random() * Math.PI * 2,
        value: ORB_BASE_SCORE,
      });
    }
  }

  private spawnObstacle() {
    if (!this.modeConfig.hasObstacles) return;

    const free = this.obstacles.find(o => !o.active);
    if (!free) return;

    // Pick a lane (or two)
    const lane = Math.floor(Math.random() * 3);
    free.lane = lane;
    free.active = true;
    free.group.visible = true;
    free.group.position.set(LANE_POSITIONS[lane], 0, SPAWN_Z);
    free.group.rotation.y = Math.random() * Math.PI * 2;

    // Sometimes spawn a second obstacle in adjacent lane for harder difficulty
    if (this.speed > 20 && Math.random() < 0.3) {
      const free2 = this.obstacles.find(o => !o.active);
      if (free2) {
        const otherLanes = [0, 1, 2].filter(l => l !== lane);
        const lane2 = otherLanes[Math.floor(Math.random() * otherLanes.length)];
        free2.lane = lane2;
        free2.active = true;
        free2.group.visible = true;
        free2.group.position.set(LANE_POSITIONS[lane2], 0, SPAWN_Z);
        free2.group.rotation.y = Math.random() * Math.PI * 2;
      }
    }
  }

  private spawnCollectible() {
    const free = this.collectibles.find(c => !c.active);
    if (!free) return;

    const lane = Math.floor(Math.random() * 3);
    free.lane = lane;
    free.active = true;
    free.mesh.visible = true;
    free.mesh.position.set(LANE_POSITIONS[lane], 1, SPAWN_Z);
    free.value = ORB_BASE_SCORE * (1 + Math.floor(this.distance / 500));
  }

  private deactivateObstacle(o: ObstacleObj) {
    o.active = false;
    o.group.visible = false;
    o.group.position.z = SPAWN_Z - 100;
  }

  private deactivateCollectible(c: CollectibleObj) {
    c.active = false;
    c.mesh.visible = false;
    c.mesh.position.z = SPAWN_Z - 100;
  }

  // ── Particle System ──────────────────────────────────────

  private createParticlePool() {
    for (let i = 0; i < PARTICLE_POOL_SIZE; i++) {
      const geo = new SphereGeometry(0.05, 4, 4);
      const mat = new MeshBasicMaterial({
        color: 0x00ffff,
        transparent: true,
        opacity: 1,
        blending: AdditiveBlending,
      });
      const mesh = new Mesh(geo, mat);
      mesh.visible = false;
      this.scene.add(mesh);
      this.particles.push({ mesh, active: false, vx: 0, vy: 0, vz: 0, life: 0, maxLife: 1 });
    }
  }

  emitParticles(x: number, y: number, z: number, color: Color, count: number, spread: number, lifetime: number) {
    let emitted = 0;
    for (const p of this.particles) {
      if (p.active || emitted >= count) continue;
      p.active = true;
      p.mesh.visible = true;
      p.mesh.position.set(x, y, z);
      (p.mesh.material as MeshBasicMaterial).color.copy(color);
      (p.mesh.material as MeshBasicMaterial).opacity = 1;
      p.vx = (Math.random() - 0.5) * spread;
      p.vy = Math.random() * spread * 0.7 + 1;
      p.vz = (Math.random() - 0.5) * spread;
      p.life = lifetime;
      p.maxLife = lifetime;
      emitted++;
    }
  }

  private updateParticles(dt: number) {
    for (const p of this.particles) {
      if (!p.active) continue;
      p.mesh.position.x += p.vx * dt;
      p.mesh.position.y += p.vy * dt;
      p.mesh.position.z += p.vz * dt;
      p.vy -= 3 * dt; // gravity
      p.life -= dt;
      const frac = Math.max(0, p.life / p.maxLife);
      (p.mesh.material as MeshBasicMaterial).opacity = frac;
      p.mesh.scale.setScalar(0.5 + frac * 0.5);
      if (p.life <= 0) {
        p.active = false;
        p.mesh.visible = false;
      }
    }
  }

  private deactivateAllParticles() {
    for (const p of this.particles) {
      p.active = false;
      p.mesh.visible = false;
    }
  }

  // ── Power-Up System ─────────────────────────────────────

  private createPowerUpPool() {
    const types: Array<{ type: PowerUpType; color: Color; geoFn: () => SphereGeometry | TorusGeometry | OctahedronGeometry | ConeGeometry }> = [
      { type: PowerUpType.SHIELD, color: new Color(0x4488ff),
        geoFn: () => new TorusGeometry(0.25, 0.08, 8, 16) },
      { type: PowerUpType.MAGNET, color: new Color(0xffcc00),
        geoFn: () => new OctahedronGeometry(0.22, 0) },
      { type: PowerUpType.SLOW_MO, color: new Color(0xaa44ff),
        geoFn: () => new ConeGeometry(0.2, 0.4, 6) },
    ];

    for (const def of types) {
      for (let i = 0; i < POWERUP_POOL_PER_TYPE; i++) {
        const group = new Group();
        const mat = new MeshStandardMaterial({
          color: def.color.clone().multiplyScalar(0.3),
          emissive: def.color,
          emissiveIntensity: 3,
          transparent: true,
          opacity: 0.9,
        });
        const main = new Mesh(def.geoFn(), mat);
        main.position.y = 1;
        group.add(main);

        const glowMat = new MeshBasicMaterial({
          color: def.color,
          transparent: true,
          opacity: 0.25,
          blending: AdditiveBlending,
        });
        const glow = new Mesh(new SphereGeometry(0.35, 8, 8), glowMat);
        glow.position.y = 1;
        group.add(glow);

        group.visible = false;
        this.scene.add(group);
        this.powerUps.push({ group, type: def.type, lane: 1, active: false });
      }
    }
  }

  private spawnPowerUp() {
    const types = [PowerUpType.SHIELD, PowerUpType.MAGNET, PowerUpType.SLOW_MO];
    const type = types[Math.floor(Math.random() * types.length)];

    const free = this.powerUps.find(p => !p.active && p.type === type);
    if (!free) return;

    const lane = Math.floor(Math.random() * 3);
    free.lane = lane;
    free.active = true;
    free.group.visible = true;
    free.group.position.set(LANE_POSITIONS[lane], 0, SPAWN_Z);
  }

  private updatePowerUps(dt: number, time: number) {
    for (const p of this.powerUps) {
      if (!p.active) continue;

      p.group.position.z += this.speed * dt;
      p.group.rotation.y += dt * 4;

      // Pulse glow
      const child = p.group.children[1];
      if (child) {
        const s = 1 + Math.sin(time * 6) * 0.2;
        child.scale.setScalar(s);
      }

      if (p.group.position.z > DESPAWN_Z) {
        p.active = false;
        p.group.visible = false;
        continue;
      }

      // Collection check
      const dx = Math.abs(p.group.position.x - this.playerX);
      const dz = Math.abs(p.group.position.z - this.playerMesh.position.z);
      if (dx < 1.2 && dz < 1) {
        this.collectPowerUp(p);
      }
    }
  }

  private collectPowerUp(p: PowerUpObj) {
    p.active = false;
    p.group.visible = false;
    this.powerUpsCollected++;

    // Get color for particles
    const colorMap: Record<string, Color> = {
      [PowerUpType.SHIELD]: new Color(0x4488ff),
      [PowerUpType.MAGNET]: new Color(0xffcc00),
      [PowerUpType.SLOW_MO]: new Color(0xaa44ff),
    };
    this.emitParticles(
      p.group.position.x, 1, p.group.position.z,
      colorMap[p.type] || new Color(0xffffff), 10, 3, 0.6,
    );

    // Audio
    this.audio?.playPowerUp(p.type);

    this.activePowerUp = p.type;
    if (p.type === PowerUpType.SHIELD) {
      this.hasShield = true;
      this.powerUpTimer = 999; // shield lasts until used
      this.powerUpMaxTime = 999;
    } else if (p.type === PowerUpType.MAGNET) {
      this.powerUpTimer = POWERUP_MAGNET_DURATION;
      this.powerUpMaxTime = POWERUP_MAGNET_DURATION;
    } else if (p.type === PowerUpType.SLOW_MO) {
      this.powerUpTimer = POWERUP_SLOWMO_DURATION;
      this.powerUpMaxTime = POWERUP_SLOWMO_DURATION;
    }
  }

  private updateActivePowerUp(dt: number) {
    if (this.activePowerUp === null) return;
    if (this.activePowerUp === PowerUpType.SHIELD) return; // shield stays until used

    this.powerUpTimer -= dt;
    if (this.powerUpTimer <= 0) {
      this.activePowerUp = null;
      this.powerUpTimer = 0;
    }
  }

  private deactivateAllPowerUps() {
    for (const p of this.powerUps) {
      p.active = false;
      p.group.visible = false;
    }
    this.activePowerUp = null;
    this.powerUpTimer = 0;
    this.hasShield = false;
  }

  // ── Challenge Wave System ───────────────────────────────

  private updateChallengeWaves(dt: number) {
    if (this.inWaveRest) {
      this.challengeRestTimer -= dt;
      if (this.challengeRestTimer <= 0) {
        this.inWaveRest = false;
        this.challengeWave = (this.challengeWave + 1) % CHALLENGE_WAVES.length;
        this.challengeWaveNum = this.challengeWave + 1;
        this.challengeWaveTimer = CHALLENGE_WAVES[this.challengeWave].duration;
        this.waveSpawnTimer = 0;
        this.wavePatternIdx = 0;
      }
      return;
    }

    const wave = CHALLENGE_WAVES[this.challengeWave];
    this.challengeWaveTimer -= dt;
    this.waveSpawnTimer += dt;

    if (this.waveSpawnTimer >= wave.spawnInterval) {
      this.waveSpawnTimer = 0;
      this.spawnChallengeObstacles(wave.patterns[this.wavePatternIdx]);
      this.wavePatternIdx = (this.wavePatternIdx + 1) % wave.patterns.length;
    }

    if (this.challengeWaveTimer <= 0) {
      this.inWaveRest = true;
      this.challengeRestTimer = WAVE_REST_DURATION;
    }
  }

  private spawnChallengeObstacles(lanesToBlock: number[]) {
    for (const lane of lanesToBlock) {
      const free = this.obstacles.find(o => !o.active);
      if (!free) return;
      free.lane = lane;
      free.active = true;
      free.group.visible = true;
      free.group.position.set(LANE_POSITIONS[lane], 0, SPAWN_Z);
      free.group.rotation.y = Math.random() * Math.PI * 2;
    }
  }

  // ── Environment Color Progression ───────────────────────

  private updateEnvironmentColors() {
    if (!this.corridorRefs) return;
    const d = this.distance;

    // Find current zone pair
    let idx = 0;
    while (idx < ENV_COLOR_ZONES.length - 1 && d >= ENV_COLOR_ZONES[idx + 1].dist) idx++;

    if (idx >= ENV_COLOR_ZONES.length - 1) {
      const z = ENV_COLOR_ZONES[ENV_COLOR_ZONES.length - 1];
      this._tmpPrimary.copy(z.primary);
      this._tmpWall.copy(z.wallEmissive);
      this._tmpFloor.copy(z.floorEmissive);
      this._tmpBg.copy(z.bg);
    } else {
      const a = ENV_COLOR_ZONES[idx];
      const b = ENV_COLOR_ZONES[idx + 1];
      const t = Math.min(1, (d - a.dist) / (b.dist - a.dist));
      this._tmpPrimary.lerpColors(a.primary, b.primary, t);
      this._tmpWall.lerpColors(a.wallEmissive, b.wallEmissive, t);
      this._tmpFloor.lerpColors(a.floorEmissive, b.floorEmissive, t);
      this._tmpBg.lerpColors(a.bg, b.bg, t);
    }

    const cr = this.corridorRefs;
    cr.gridMat.color.copy(this._tmpPrimary);
    cr.laneMat.color.copy(this._tmpPrimary);
    cr.trimMat.color.copy(this._tmpPrimary);
    cr.beamMat.emissive.copy(this._tmpPrimary);
    cr.beamMat.emissiveIntensity = 0.4;
    cr.wallMat.emissive.copy(this._tmpWall);
    cr.floorMat.emissive.copy(this._tmpFloor);
    for (const light of cr.pointLights) light.color.copy(this._tmpPrimary);

    // Update scene bg and fog
    const bg = this.scene.background;
    if (bg && 'isColor' in bg) (bg as Color).copy(this._tmpBg);
    const fog = this.scene.fog;
    if (fog && 'color' in fog) (fog as unknown as { color: Color }).color.copy(this._tmpBg);
  }

  // ── Screen Shake ────────────────────────────────────────

  private updateScreenShake(dt: number) {
    if (this.shakeIntensity > 0) {
      this.shakeIntensity *= Math.exp(-SHAKE_DECAY * dt);
      if (this.shakeIntensity < 0.001) {
        this.shakeIntensity = 0;
        this.camera.position.x = 0;
        this.camera.position.y = 1.6;
      } else {
        this.camera.position.x = (Math.random() - 0.5) * this.shakeIntensity;
        this.camera.position.y = 1.6 + (Math.random() - 0.5) * this.shakeIntensity * 0.5;
      }
    }
  }

  // ── Public API for UI System ──────────────────────────────

  startGame(mode: GameMode = GameMode.CLASSIC) {
    this.mode = mode;
    this.modeConfig = GAME_MODES[mode];
    this.state = GameState.COUNTDOWN;
    this.countdownValue = 3;
    this.countdownTimer = 0;

    // Reset game state
    this.score = 0;
    this.distance = 0;
    this.speed = BASE_SPEED * this.modeConfig.speedMultiplier;
    this.lives = this.modeConfig.lives;
    this.multiplier = 1;
    this.multiplierTimer = 0;
    this.orbsCollected = 0;
    this.totalOrbsThisRun = 0;
    this.invincibilityTimer = 0;
    this.elapsedTime = 0;
    this.maxSpeed = this.speed;
    this.playerLane = 1;
    this.playerX = 0;
    this.targetX = 0;
    this.laneSwitchCooldown = 0;
    this.obstacleSpawnTimer = 0;
    this.collectibleSpawnTimer = 0;
    this.isNewRecord = false;
    this.longestCombo = 0;
    this.currentCombo = 0;
    this.challengeWave = 0;
    this.challengeTimer = 0;

    // Reset Round 2 state
    this.deactivateAllParticles();
    this.deactivateAllPowerUps();
    this.powerUpSpawnTimer = 0;
    this.powerUpsCollected = 0;
    this.challengeWaveTimer = 0;
    this.challengeRestTimer = 0;
    this.inWaveRest = false;
    this.waveSpawnTimer = 0;
    this.wavePatternIdx = 0;
    this.challengeWaveNum = 0;
    this.shakeIntensity = 0;

    // Init challenge wave if in challenge mode
    if (mode === GameMode.CHALLENGE) {
      this.challengeWaveNum = 1;
      this.challengeWaveTimer = CHALLENGE_WAVES[0].duration;
    }

    // Clear all active objects
    for (const o of this.obstacles) this.deactivateObstacle(o);
    for (const c of this.collectibles) this.deactivateCollectible(c);

    // Show player
    this.showPlayerVisual();
    this.playerMesh.position.x = 0;
    this.playerGlow.position.x = 0;

    // Mode-specific achievements
    const modeAchMap: Record<string, string> = {
      classic: 'mode-classic', sprint: 'mode-sprint', time_attack: 'mode-time',
      zen: 'mode-zen', endless: 'mode-endless', challenge: 'mode-challenge',
    };
    if (modeAchMap[mode]) this.unlockAchievement(modeAchMap[mode]);
  }

  pauseGame() {
    if (this.state === GameState.PLAYING) {
      this.state = GameState.PAUSED;
    }
  }

  resumeGame() {
    if (this.state === GameState.PAUSED) {
      this.state = GameState.PLAYING;
    }
  }

  quitToMenu() {
    this.state = GameState.MENU;
    this.hidePlayerVisual();
    for (const o of this.obstacles) this.deactivateObstacle(o);
    for (const c of this.collectibles) this.deactivateCollectible(c);
    for (const line of this.speedLines) line.visible = false;
    this.deactivateAllParticles();
    this.deactivateAllPowerUps();
    this.shakeIntensity = 0;
    this.camera.position.set(0, 1.6, 0);
  }

  showModeSelect() { this.state = GameState.MODE_SELECT; }
  showSettings() { this.state = GameState.SETTINGS; }
  showAchievements() { this.state = GameState.ACHIEVEMENTS; }
  showTutorial() { this.state = GameState.TUTORIAL; }
  showStats() { this.state = GameState.STATS; }
  showMenu() { this.state = GameState.MENU; }

  getAchievementCount(): number {
    return this.achievements.filter(a => a.unlocked).length;
  }

  // ── Main Update Loop ─────────────────────────────────────

  update(delta: number, time: number) {
    // Clamp large deltas
    const dt = Math.min(delta, 0.1);

    switch (this.state) {
      case GameState.COUNTDOWN:
        this.updateCountdown(dt);
        break;
      case GameState.PLAYING:
        this.updatePlaying(dt, time);
        break;
      case GameState.PAUSED:
        // Just animate player glow
        this.animatePlayerGlow(time);
        break;
      default:
        break;
    }
  }

  private updateCountdown(dt: number) {
    this.countdownTimer += dt;
    if (this.countdownTimer >= 1) {
      this.countdownTimer -= 1;
      this.countdownValue--;
      this.audio?.playCountdown(this.countdownValue);
      if (this.countdownValue <= 0) {
        this.state = GameState.PLAYING;
      }
    }
  }

  private updatePlaying(dt: number, time: number) {
    this.elapsedTime += dt;

    // Speed increase
    this.speed = Math.min(
      MAX_SPEED,
      (BASE_SPEED * this.modeConfig.speedMultiplier) + this.elapsedTime * SPEED_INCREASE_RATE,
    );
    // Slow-Mo power-up
    if (this.activePowerUp === PowerUpType.SLOW_MO) {
      this.speed *= POWERUP_SLOWMO_FACTOR;
    }
    this.maxSpeed = Math.max(this.maxSpeed, this.speed);

    // Distance
    this.distance += this.speed * dt;
    this.score += this.speed * dt * DISTANCE_SCORE_RATE * 0.1;

    // Multiplier decay
    this.multiplierTimer += dt;
    if (this.multiplierTimer > MULTIPLIER_DECAY_TIME && this.multiplier > 1) {
      this.multiplier = Math.max(1, this.multiplier - 1);
      this.multiplierTimer = 0;
      this.currentCombo = 0;
    }

    // Invincibility
    if (this.invincibilityTimer > 0) {
      this.invincibilityTimer -= dt;
      // Flash player
      this.playerMesh.visible = Math.sin(time * 20) > 0;
    }

    // Cooldowns
    if (this.laneSwitchCooldown > 0) this.laneSwitchCooldown -= dt;

    // Input
    this.handleInput();

    // Player position lerp
    this.targetX = LANE_POSITIONS[this.playerLane];
    this.playerX += (this.targetX - this.playerX) * LANE_SWITCH_SPEED * dt;
    this.playerMesh.position.x = this.playerX;
    this.playerGlow.position.x = this.playerX;

    // Player rotation (lean into turns)
    const leanAngle = (this.targetX - this.playerX) * 0.3;
    this.playerMesh.rotation.z = leanAngle;
    this.playerMesh.rotation.y += dt * 2;

    // Animate player glow
    this.animatePlayerGlow(time);

    // Move and spawn objects
    this.updateObstacles(dt);
    this.updateCollectibles(dt, time);

    // Obstacle spawning: challenge mode uses wave system, others use random
    if (this.mode === GameMode.CHALLENGE) {
      this.updateChallengeWaves(dt);
    } else {
      const speedFraction = this.speed / MAX_SPEED;
      const obstacleInterval = OBSTACLE_BASE_INTERVAL - speedFraction * (OBSTACLE_BASE_INTERVAL - OBSTACLE_MIN_INTERVAL);
      this.obstacleSpawnTimer += dt;
      if (this.obstacleSpawnTimer >= obstacleInterval) {
        this.obstacleSpawnTimer = 0;
        this.spawnObstacle();
      }
    }

    this.collectibleSpawnTimer += dt;
    if (this.collectibleSpawnTimer >= COLLECTIBLE_INTERVAL) {
      this.collectibleSpawnTimer = 0;
      this.spawnCollectible();
    }

    // Round 2 updates
    this.updateParticles(dt);
    this.updatePowerUps(dt, time);
    this.updateActivePowerUp(dt);
    this.updateEnvironmentColors();
    this.updateScreenShake(dt);

    // Power-up spawning
    this.powerUpSpawnTimer += dt;
    if (this.powerUpSpawnTimer >= POWERUP_SPAWN_INTERVAL) {
      this.powerUpSpawnTimer = 0;
      this.spawnPowerUp();
    }

    // Speed trail particles at high speed
    if (this.speed > 25 && Math.random() < 0.3) {
      const trailColor = new Color(0x0088ff);
      this.emitParticles(
        this.playerX + (Math.random() - 0.5) * 0.3,
        0.5 + Math.random() * 0.2,
        this.playerMesh.position.z + 0.3,
        trailColor, 1, 0.5, 0.3,
      );
    }

    // Speed lines
    this.updateSpeedLines(dt);

    // Check achievements
    this.checkAchievements();

    // Time limit check
    if (this.modeConfig.timeLimit > 0 && this.elapsedTime >= this.modeConfig.timeLimit) {
      this.endGame();
      return;
    }

    // Sprint target check
    if (this.modeConfig.targetDistance > 0 && this.distance >= this.modeConfig.targetDistance) {
      this.unlockAchievement('perfect-sprint');
      this.endGame();
      return;
    }

    // First run achievement
    this.unlockAchievement('first-run');
  }

  private animatePlayerGlow(time: number) {
    const scale = 1 + Math.sin(time * 3) * 0.15;
    this.playerGlow.scale.setScalar(scale);
    const glowMat = this.playerGlow.material as MeshBasicMaterial;
    glowMat.opacity = 0.15 + Math.sin(time * 4) * 0.08;
  }

  private handleInput() {
    if (this.laneSwitchCooldown > 0) return;

    let moveLeft = false;
    let moveRight = false;

    // Keyboard
    if (this._kb().getKeyDown('KeyA') || this._kb().getKeyDown('ArrowLeft')) {
      moveLeft = true;
    }
    if (this._kb().getKeyDown('KeyD') || this._kb().getKeyDown('ArrowRight')) {
      moveRight = true;
    }

    // Pause
    if (this._kb().getKeyDown('Escape') || this._kb().getKeyDown('KeyP')) {
      this.pauseGame();
      return;
    }

    // XR controller
    const left = this.input.gamepads.left;
    const right = this.input.gamepads.right;

    if (left) {
      const stick = left.getAxesValues(InputComponent.Thumbstick);
      if (stick && Math.abs(stick.x) > 0.5) {
        if (stick.x < -0.5) moveLeft = true;
        if (stick.x > 0.5) moveRight = true;
      }
    }
    if (right) {
      const stick = right.getAxesValues(InputComponent.Thumbstick);
      if (stick && Math.abs(stick.x) > 0.5) {
        if (stick.x < -0.5) moveLeft = true;
        if (stick.x > 0.5) moveRight = true;
      }
      // Pause with B button
      if (right.getButtonDown(InputComponent.B_Button)) {
        this.pauseGame();
        return;
      }
    }

    if (moveLeft && this.playerLane > 0) {
      this.playerLane--;
      this.laneSwitchCooldown = LANE_SWITCH_COOLDOWN;
      this.audio?.playLaneSwitch();
    }
    if (moveRight && this.playerLane < 2) {
      this.playerLane++;
      this.laneSwitchCooldown = LANE_SWITCH_COOLDOWN;
      this.audio?.playLaneSwitch();
    }
  }

  private updateObstacles(dt: number) {
    for (const o of this.obstacles) {
      if (!o.active) continue;

      o.group.position.z += this.speed * dt;
      o.group.rotation.y += dt * 0.5;

      // Despawn
      if (o.group.position.z > DESPAWN_Z) {
        this.deactivateObstacle(o);
        continue;
      }

      // Collision check
      if (this.invincibilityTimer <= 0) {
        const dx = Math.abs(o.group.position.x - this.playerX);
        const dz = Math.abs(o.group.position.z - this.playerMesh.position.z);
        if (dx < 0.8 && dz < 0.6) {
          this.onHit();
        }
      }
    }
  }

  private updateCollectibles(dt: number, time: number) {
    for (const c of this.collectibles) {
      if (!c.active) continue;

      c.mesh.position.z += this.speed * dt;
      c.mesh.rotation.y += dt * 3;
      c.mesh.position.y = 1 + Math.sin(time * 4 + c.pulsePhase) * 0.15;

      // Pulse scale
      const pulse = 1 + Math.sin(time * 5 + c.pulsePhase) * 0.1;
      c.mesh.scale.setScalar(pulse);

      // Despawn
      if (c.mesh.position.z > DESPAWN_Z) {
        this.deactivateCollectible(c);
        this.currentCombo = 0;
        continue;
      }

      // Collection check (expanded range with Magnet power-up)
      const dx = Math.abs(c.mesh.position.x - this.playerX);
      const dz = Math.abs(c.mesh.position.z - this.playerMesh.position.z);
      const collectRange = (this.activePowerUp === PowerUpType.MAGNET) ? 2.5 : 1;
      if (dx < collectRange && dz < 1) {
        this.collectOrb(c);
      }
    }
  }

  private collectOrb(c: CollectibleObj) {
    // Emit collection particles
    const orbColor = COLLECTIBLE_COLORS[Math.floor(Math.random() * COLLECTIBLE_COLORS.length)];
    this.emitParticles(c.mesh.position.x, c.mesh.position.y, c.mesh.position.z, orbColor, 8, 3, 0.5);

    this.score += c.value * this.multiplier;
    this.orbsCollected++;
    this.totalOrbsThisRun++;
    this.currentCombo++;
    this.longestCombo = Math.max(this.longestCombo, this.currentCombo);
    this.multiplierTimer = 0;

    // Audio
    this.audio?.playOrbCollect(this.multiplier);

    // Increase multiplier every 3 orbs
    if (this.currentCombo % 3 === 0 && this.multiplier < MAX_MULTIPLIER) {
      this.multiplier++;
      this.audio?.playMultiplierUp(this.multiplier);
    }

    this.deactivateCollectible(c);
  }

  private onHit() {
    // Shield power-up absorbs the hit
    if (this.hasShield) {
      this.hasShield = false;
      this.activePowerUp = null;
      this.powerUpTimer = 0;
      this.emitParticles(this.playerX, 0.8, this.playerMesh.position.z,
        new Color(0x4488ff), 15, 5, 0.8);
      if (this.screenShakeEnabled) this.shakeIntensity = 0.08;
      this.audio?.playShieldBreak();
      return;
    }

    // Hit particles
    const hitColor = OBSTACLE_COLORS[Math.floor(Math.random() * OBSTACLE_COLORS.length)];
    this.emitParticles(this.playerX, 0.6, this.playerMesh.position.z, hitColor, 12, 4, 0.6);

    // Screen shake
    if (this.screenShakeEnabled) this.shakeIntensity = 0.15;

    // Audio
    this.audio?.playHit();

    this.lives--;
    this.multiplier = 1;
    this.currentCombo = 0;
    this.invincibilityTimer = INVINCIBILITY_TIME;

    if (this.lives <= 0) {
      this.endGame();
    }
  }

  private endGame() {
    this.state = GameState.GAME_OVER;

    // Record lifetime stats
    if (this.stats) {
      this.stats.recordRun({
        mode: this.mode,
        distance: this.distance,
        orbs: this.totalOrbsThisRun,
        score: this.score,
        time: this.elapsedTime,
        powerUps: this.powerUpsCollected,
        maxSpeed: this.maxSpeed,
        longestCombo: this.longestCombo,
        bestMultiplier: this.multiplier,
      });
    }

    // Check/save high score
    const key = this.mode;
    const prev = this.highScores[key] || 0;
    if (this.score > prev) {
      this.highScores[key] = Math.floor(this.score);
      this.isNewRecord = true;
      this.saveHighScores();
      this.audio?.playNewRecord();
    } else {
      this.audio?.playGameOver();
    }

    this.hidePlayerVisual();
    for (const line of this.speedLines) line.visible = false;
    this.deactivateAllPowerUps();
    this.shakeIntensity = 0;
    this.camera.position.set(0, 1.6, 0);
  }
}

import {
  createSystem,
  PanelUI,
  PanelDocument,
  UIKitDocument,
  UIKit,
  eq,
  Entity,
} from '@iwsdk/core';

import { GameSystem, GameState, GameMode, GAME_MODES, PowerUpType } from './game-system.js';
import type { AudioManager } from './audio-system.js';
import type { StatsTracker } from './stats-tracker.js';
import { StatsTracker as StatsTrackerClass } from './stats-tracker.js';

// ── Helper ────────────────────────────────────────────────────

const getDoc = (e: Entity) =>
  e.getValue(PanelDocument, 'document') as UIKitDocument | undefined;

const setText = (doc: UIKitDocument | undefined, id: string, text: string) =>
  (doc?.getElementById(id) as UIKit.Text | undefined)?.setProperties({ text });

const setVisible = (doc: UIKitDocument | undefined, id: string, visible: boolean) =>
  (doc?.getElementById(id) as UIKit.Text | undefined)?.setProperties({
    display: visible ? ('flex' as any) : ('none' as any),
  });

// ── UISystem ─────────────────────────────────────────────────

export class UISystem extends createSystem({
  menu: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/main-menu.json')],
  },
  hud: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/hud.json')],
  },
  gameOver: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/game-over.json')],
  },
  pause: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/pause-menu.json')],
  },
  modeSelect: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/mode-select.json')],
  },
  settings: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/settings.json')],
  },
  achievements: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/achievements.json')],
  },
  tutorial: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/tutorial.json')],
  },
  countdown: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/countdown.json')],
  },
  newRecord: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/new-record.json')],
  },
  stats: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/stats.json')],
  },
}) {
  private gameSystem!: GameSystem;
  private audio!: AudioManager;
  private statsTracker!: StatsTracker;
  private prevState: GameState | null = null;
  private achievementToast = '';
  private achievementToastTimer = 0;
  private lastHudUpdate = 0;

  /** Hide/show an entity based on current game state */
  private syncVisibility(entity: Entity, shouldShow: boolean) {
    if (entity?.object3D) entity.object3D.visible = shouldShow;
  }

  // Panel entities (set on qualify)
  private menuEntity: Entity | null = null;
  private hudEntity: Entity | null = null;
  private gameOverEntity: Entity | null = null;
  private pauseEntity: Entity | null = null;
  private modeSelectEntity: Entity | null = null;
  private settingsEntity: Entity | null = null;
  private achievementsEntity: Entity | null = null;
  private tutorialEntity: Entity | null = null;
  private countdownEntity: Entity | null = null;
  private newRecordEntity: Entity | null = null;
  private statsEntity: Entity | null = null;

  setRefs(refs: { gameSystem: GameSystem; audioManager?: AudioManager; statsTracker?: StatsTracker }) {
    this.gameSystem = refs.gameSystem;
    if (refs.audioManager) this.audio = refs.audioManager;
    if (refs.statsTracker) this.statsTracker = refs.statsTracker;
  }

  init() {
    // Main menu
    this.queries.menu.subscribe('qualify', (entity) => {
      this.menuEntity = entity;
      this.syncVisibility(entity, this.gameSystem.state === GameState.MENU);
      const doc = getDoc(entity);
      if (!doc) return;

      const playBtn = doc.getElementById('btn-play') as UIKit.Text | undefined;
      playBtn?.addEventListener('click', () => {
        this.audio?.playClick();
        this.gameSystem.startGame(GameMode.CLASSIC);
      });

      const modesBtn = doc.getElementById('btn-modes') as UIKit.Text | undefined;
      modesBtn?.addEventListener('click', () => {
        this.audio?.playClick();
        this.gameSystem.showModeSelect();
      });

      const settingsBtn = doc.getElementById('btn-settings') as UIKit.Text | undefined;
      settingsBtn?.addEventListener('click', () => {
        this.audio?.playClick();
        this.gameSystem.showSettings();
      });

      const achievementsBtn = doc.getElementById('btn-achievements') as UIKit.Text | undefined;
      achievementsBtn?.addEventListener('click', () => {
        this.audio?.playClick();
        this.gameSystem.showAchievements();
      });

      const tutorialBtn = doc.getElementById('btn-tutorial') as UIKit.Text | undefined;
      tutorialBtn?.addEventListener('click', () => {
        this.audio?.playClick();
        this.gameSystem.showTutorial();
      });

      const statsBtn = doc.getElementById('btn-stats') as UIKit.Text | undefined;
      statsBtn?.addEventListener('click', () => {
        this.audio?.playClick();
        this.gameSystem.showStats();
      });
    });

    // HUD
    this.queries.hud.subscribe('qualify', (entity) => {
      this.hudEntity = entity;
      this.syncVisibility(entity, false);
    });

    // Game Over
    this.queries.gameOver.subscribe('qualify', (entity) => {
      this.gameOverEntity = entity;
      this.syncVisibility(entity, false);
      const doc = getDoc(entity);
      if (!doc) return;

      const retryBtn = doc.getElementById('btn-retry') as UIKit.Text | undefined;
      retryBtn?.addEventListener('click', () => {
        this.audio?.playClick();
        this.gameSystem.startGame(this.gameSystem.mode);
      });

      const menuBtn = doc.getElementById('btn-menu') as UIKit.Text | undefined;
      menuBtn?.addEventListener('click', () => {
        this.audio?.playClick();
        this.gameSystem.quitToMenu();
      });
    });

    // Pause Menu
    this.queries.pause.subscribe('qualify', (entity) => {
      this.pauseEntity = entity;
      this.syncVisibility(entity, false);
      const doc = getDoc(entity);
      if (!doc) return;

      const resumeBtn = doc.getElementById('btn-resume') as UIKit.Text | undefined;
      resumeBtn?.addEventListener('click', () => {
        this.audio?.playClick();
        this.gameSystem.resumeGame();
      });

      const quitBtn = doc.getElementById('btn-quit') as UIKit.Text | undefined;
      quitBtn?.addEventListener('click', () => {
        this.audio?.playClick();
        this.gameSystem.quitToMenu();
      });
    });

    // Mode Select
    this.queries.modeSelect.subscribe('qualify', (entity) => {
      this.modeSelectEntity = entity;
      this.syncVisibility(entity, false);
      const doc = getDoc(entity);
      if (!doc) return;

      const modes = [GameMode.CLASSIC, GameMode.SPRINT, GameMode.TIME_ATTACK, GameMode.ZEN, GameMode.ENDLESS, GameMode.CHALLENGE];
      for (const mode of modes) {
        const btn = doc.getElementById(`btn-${mode}`) as UIKit.Text | undefined;
        btn?.addEventListener('click', () => {
          this.audio?.playClick();
          this.gameSystem.startGame(mode);
        });
      }

      const backBtn = doc.getElementById('btn-back') as UIKit.Text | undefined;
      backBtn?.addEventListener('click', () => {
        this.audio?.playClick();
        this.gameSystem.showMenu();
      });
    });

    // Settings
    this.queries.settings.subscribe('qualify', (entity) => {
      this.settingsEntity = entity;
      this.syncVisibility(entity, false);
      const doc = getDoc(entity);
      if (!doc) return;

      const backBtn = doc.getElementById('btn-back') as UIKit.Text | undefined;
      backBtn?.addEventListener('click', () => {
        this.audio?.playClick();
        this.gameSystem.showMenu();
      });

      // Sound toggle
      const soundBtn = doc.getElementById('btn-toggle-sound') as UIKit.Text | undefined;
      soundBtn?.addEventListener('click', () => {
        if (this.audio) {
          this.audio.muted = !this.audio.muted;
          setText(doc, 'btn-toggle-sound', this.audio.muted ? 'OFF' : 'ON');
        }
        this.audio?.playClick();
      });

      // Volume controls
      const volDown = doc.getElementById('btn-vol-down') as UIKit.Text | undefined;
      volDown?.addEventListener('click', () => {
        if (this.audio) {
          this.audio.volume = Math.max(0, this.audio.volume - 0.1);
          setText(doc, 'volume-display', `${Math.round(this.audio.volume * 100)}%`);
        }
        this.audio?.playClick();
      });

      const volUp = doc.getElementById('btn-vol-up') as UIKit.Text | undefined;
      volUp?.addEventListener('click', () => {
        if (this.audio) {
          this.audio.volume = Math.min(1, this.audio.volume + 0.1);
          setText(doc, 'volume-display', `${Math.round(this.audio.volume * 100)}%`);
        }
        this.audio?.playClick();
      });

      // Screen shake toggle
      const shakeBtn = doc.getElementById('btn-toggle-shake') as UIKit.Text | undefined;
      shakeBtn?.addEventListener('click', () => {
        this.gameSystem.screenShakeEnabled = !this.gameSystem.screenShakeEnabled;
        setText(doc, 'btn-toggle-shake', this.gameSystem.screenShakeEnabled ? 'ON' : 'OFF');
        this.gameSystem.savePrefs();
        this.audio?.playClick();
      });

      // Speed lines toggle
      const linesBtn = doc.getElementById('btn-toggle-lines') as UIKit.Text | undefined;
      linesBtn?.addEventListener('click', () => {
        this.gameSystem.speedLinesEnabled = !this.gameSystem.speedLinesEnabled;
        setText(doc, 'btn-toggle-lines', this.gameSystem.speedLinesEnabled ? 'ON' : 'OFF');
        this.gameSystem.savePrefs();
        this.audio?.playClick();
      });

      // Reset buttons
      const resetScoresBtn = doc.getElementById('btn-reset-scores') as UIKit.Text | undefined;
      resetScoresBtn?.addEventListener('click', () => {
        this.gameSystem.resetHighScores();
        this.audio?.playClick();
      });

      const resetAllBtn = doc.getElementById('btn-reset-all') as UIKit.Text | undefined;
      resetAllBtn?.addEventListener('click', () => {
        this.gameSystem.resetAllData();
        this.audio?.playClick();
      });
    });

    // Achievements
    this.queries.achievements.subscribe('qualify', (entity) => {
      this.achievementsEntity = entity;
      this.syncVisibility(entity, false);
      const doc = getDoc(entity);
      if (!doc) return;

      const backBtn = doc.getElementById('btn-back') as UIKit.Text | undefined;
      backBtn?.addEventListener('click', () => {
        this.audio?.playClick();
        this.gameSystem.showMenu();
      });
    });

    // Tutorial
    this.queries.tutorial.subscribe('qualify', (entity) => {
      this.tutorialEntity = entity;
      this.syncVisibility(entity, false);
      const doc = getDoc(entity);
      if (!doc) return;

      const backBtn = doc.getElementById('btn-back') as UIKit.Text | undefined;
      backBtn?.addEventListener('click', () => {
        this.audio?.playClick();
        this.gameSystem.showMenu();
      });

      const playBtn = doc.getElementById('btn-play') as UIKit.Text | undefined;
      playBtn?.addEventListener('click', () => {
        this.audio?.playClick();
        this.gameSystem.startGame(GameMode.CLASSIC);
      });
    });

    // Countdown
    this.queries.countdown.subscribe('qualify', (entity) => {
      this.countdownEntity = entity;
      this.syncVisibility(entity, false);
    });

    // New Record
    this.queries.newRecord.subscribe('qualify', (entity) => {
      this.newRecordEntity = entity;
      this.syncVisibility(entity, false);
    });

    // Stats
    this.queries.stats.subscribe('qualify', (entity) => {
      this.statsEntity = entity;
      this.syncVisibility(entity, false);
      const doc = getDoc(entity);
      if (!doc) return;

      const backBtn = doc.getElementById('btn-back') as UIKit.Text | undefined;
      backBtn?.addEventListener('click', () => {
        this.audio?.playClick();
        this.gameSystem.showMenu();
      });
    });
  }

  showAchievementToast(name: string) {
    this.achievementToast = name;
    this.achievementToastTimer = 3;
  }

  update(delta: number, _time: number) {
    const dt = Math.min(delta, 0.1);
    const state = this.gameSystem.state;

    // State changed - update visibility
    if (state !== this.prevState) {
      this.updatePanelVisibility(state);
      this.prevState = state;

      // Update content on state enter
      if (state === GameState.GAME_OVER) this.updateGameOverPanel();
      if (state === GameState.ACHIEVEMENTS) this.updateAchievementsPanel();
      if (state === GameState.STATS) this.updateStatsPanel();
      if (state === GameState.MENU) this.updateMainMenuPanel();
      if (state === GameState.SETTINGS) this.updateSettingsPanel();
    }

    // Continuous updates
    if (state === GameState.PLAYING) {
      this.lastHudUpdate += dt;
      if (this.lastHudUpdate > 0.1) {
        this.updateHUD();
        this.lastHudUpdate = 0;
      }
    }

    if (state === GameState.COUNTDOWN) {
      this.updateCountdownPanel();
    }

    // Achievement toast
    if (this.achievementToastTimer > 0) {
      this.achievementToastTimer -= dt;
      if (this.hudEntity) {
        const doc = getDoc(this.hudEntity);
        setText(doc, 'achievement-toast', `Unlocked: ${this.achievementToast}`);
        setVisible(doc, 'achievement-toast', true);
      }
    } else if (this.hudEntity) {
      const doc = getDoc(this.hudEntity);
      setVisible(doc, 'achievement-toast', false);
    }
  }

  private updatePanelVisibility(state: GameState) {
    const show = (entity: Entity | null, visible: boolean) => {
      if (entity?.object3D) entity.object3D.visible = visible;
    };

    show(this.menuEntity, state === GameState.MENU);
    show(this.hudEntity, state === GameState.PLAYING || state === GameState.COUNTDOWN);
    show(this.gameOverEntity, state === GameState.GAME_OVER);
    show(this.pauseEntity, state === GameState.PAUSED);
    show(this.modeSelectEntity, state === GameState.MODE_SELECT);
    show(this.settingsEntity, state === GameState.SETTINGS);
    show(this.achievementsEntity, state === GameState.ACHIEVEMENTS);
    show(this.tutorialEntity, state === GameState.TUTORIAL);
    show(this.countdownEntity, state === GameState.COUNTDOWN);
    show(this.newRecordEntity, state === GameState.GAME_OVER && this.gameSystem.isNewRecord);
    show(this.statsEntity, state === GameState.STATS);
  }

  private updateHUD() {
    if (!this.hudEntity) return;
    const doc = getDoc(this.hudEntity);
    if (!doc) return;

    const gs = this.gameSystem;
    setText(doc, 'score', `Score: ${Math.floor(gs.score).toLocaleString()}`);
    setText(doc, 'distance', `${Math.floor(gs.distance)}m`);
    setText(doc, 'speed', `${gs.speed.toFixed(1)} m/s`);
    setText(doc, 'multiplier', gs.multiplier > 1 ? `x${gs.multiplier}` : '');
    setText(doc, 'orbs', `Orbs: ${gs.orbsCollected}`);

    // Lives display
    const livesText = gs.lives > 5 ? `${gs.lives}` : '*'.repeat(gs.lives);
    setText(doc, 'lives', livesText);

    // Timer (for timed modes)
    const cfg = gs.modeConfig;
    if (cfg.timeLimit > 0) {
      const remaining = Math.max(0, cfg.timeLimit - gs.elapsedTime);
      const mins = Math.floor(remaining / 60);
      const secs = Math.floor(remaining % 60);
      setText(doc, 'timer', `${mins}:${secs.toString().padStart(2, '0')}`);
      setVisible(doc, 'timer', true);
    } else {
      setVisible(doc, 'timer', false);
    }

    // Sprint progress
    if (cfg.targetDistance > 0) {
      const pct = Math.min(100, (gs.distance / cfg.targetDistance) * 100);
      setText(doc, 'progress', `${pct.toFixed(0)}%`);
      setVisible(doc, 'progress', true);
    } else {
      setVisible(doc, 'progress', false);
    }

    // Power-up status
    if (gs.activePowerUp !== null) {
      const puLabels: Record<string, string> = {
        [PowerUpType.SHIELD]: 'SHIELD',
        [PowerUpType.MAGNET]: 'MAGNET',
        [PowerUpType.SLOW_MO]: 'SLOW-MO',
      };
      const label = puLabels[gs.activePowerUp] || '';
      if (gs.activePowerUp === PowerUpType.SHIELD) {
        setText(doc, 'power-up-status', `${label} ACTIVE`);
      } else {
        setText(doc, 'power-up-status', `${label} ${gs.powerUpTimer.toFixed(1)}s`);
      }
      setVisible(doc, 'power-up-status', true);
    } else {
      setVisible(doc, 'power-up-status', false);
    }

    // Wave indicator (challenge mode)
    if (gs.mode === GameMode.CHALLENGE && gs.challengeWaveNum > 0) {
      setText(doc, 'wave-indicator', `Wave ${gs.challengeWaveNum}`);
      setVisible(doc, 'wave-indicator', true);
    } else {
      setVisible(doc, 'wave-indicator', false);
    }
  }

  private updateCountdownPanel() {
    if (!this.countdownEntity) return;
    const doc = getDoc(this.countdownEntity);
    if (!doc) return;

    const val = this.gameSystem.countdownValue;
    setText(doc, 'countdown-text', val > 0 ? `${val}` : 'GO!');
  }

  private updateGameOverPanel() {
    if (!this.gameOverEntity) return;
    const doc = getDoc(this.gameOverEntity);
    if (!doc) return;

    const gs = this.gameSystem;
    setText(doc, 'final-score', `${Math.floor(gs.score).toLocaleString()}`);
    setText(doc, 'final-distance', `${Math.floor(gs.distance)}m`);
    setText(doc, 'final-orbs', `${gs.orbsCollected}`);
    setText(doc, 'final-time', `${Math.floor(gs.elapsedTime)}s`);
    setText(doc, 'final-speed', `${gs.maxSpeed.toFixed(1)} m/s`);
    setText(doc, 'final-combo', `${gs.longestCombo}`);
    setText(doc, 'final-powerups', `${gs.powerUpsCollected}`);
    setText(doc, 'high-score', `Best: ${(gs.highScores[gs.mode] || 0).toLocaleString()}`);
    setText(doc, 'mode-name', GAME_MODES[gs.mode].name);

    // Show wave reached for challenge mode
    if (gs.mode === GameMode.CHALLENGE) {
      setText(doc, 'final-wave', `${gs.challengeWaveNum}`);
      setVisible(doc, 'wave-row', true);
    } else {
      setVisible(doc, 'wave-row', false);
    }

    if (gs.isNewRecord) {
      setVisible(doc, 'new-record-badge', true);
    } else {
      setVisible(doc, 'new-record-badge', false);
    }
  }

  private updateAchievementsPanel() {
    if (!this.achievementsEntity) return;
    const doc = getDoc(this.achievementsEntity);
    if (!doc) return;

    const gs = this.gameSystem;
    const unlocked = gs.getAchievementCount();
    const total = gs.achievements.length;
    setText(doc, 'ach-count', `${unlocked} / ${total}`);

    // Update achievement list (first 12 shown)
    for (let i = 0; i < 12; i++) {
      const a = gs.achievements[i];
      if (a) {
        setText(doc, `ach-name-${i}`, a.name);
        setText(doc, `ach-desc-${i}`, a.description);
        setText(doc, `ach-status-${i}`, a.unlocked ? '[DONE]' : '[ ]');
      }
    }
  }

  private updateStatsPanel() {
    if (!this.statsEntity || !this.statsTracker) return;
    const doc = getDoc(this.statsEntity);
    if (!doc) return;

    const s = this.statsTracker.get();
    setText(doc, 'stat-games', `${s.totalGames}`);
    setText(doc, 'stat-distance', StatsTrackerClass.formatDistance(s.totalDistance));
    setText(doc, 'stat-orbs', `${s.totalOrbs.toLocaleString()}`);
    setText(doc, 'stat-score', `${Math.floor(s.totalScore).toLocaleString()}`);
    setText(doc, 'stat-time', StatsTrackerClass.formatTime(s.totalTimePlayed));
    setText(doc, 'stat-longest', StatsTrackerClass.formatDistance(s.longestRun));
    setText(doc, 'stat-speed', `${s.highestSpeed.toFixed(1)} m/s`);
    setText(doc, 'stat-combo', `${s.longestCombo}`);
    setText(doc, 'stat-powerups', `${s.totalPowerUps}`);
  }

  private updateMainMenuPanel() {
    if (!this.menuEntity) return;
    const doc = getDoc(this.menuEntity);
    if (!doc) return;

    // Show best classic score
    const bestScore = this.gameSystem.highScores['classic'] || 0;
    if (bestScore > 0) {
      setText(doc, 'best-score', `Best: ${bestScore.toLocaleString()}`);
    } else {
      setText(doc, 'best-score', '');
    }
  }

  private updateSettingsPanel() {
    if (!this.settingsEntity) return;
    const doc = getDoc(this.settingsEntity);
    if (!doc) return;

    // Sync current values
    if (this.audio) {
      setText(doc, 'btn-toggle-sound', this.audio.muted ? 'OFF' : 'ON');
      setText(doc, 'volume-display', `${Math.round(this.audio.volume * 100)}%`);
    }
    setText(doc, 'btn-toggle-shake', this.gameSystem.screenShakeEnabled ? 'ON' : 'OFF');
    setText(doc, 'btn-toggle-lines', this.gameSystem.speedLinesEnabled ? 'ON' : 'OFF');
  }
}

/**
 * Procedural Audio System for Neon Sprint
 * Uses Web Audio API for real-time synthesized sound effects.
 * No audio files needed - all sounds are generated mathematically.
 */

export class AudioManager {
  private ctx: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private _volume = 0.5;
  private _muted = false;

  get volume() { return this._volume; }
  set volume(v: number) {
    this._volume = Math.max(0, Math.min(1, v));
    if (this.masterGain) {
      this.masterGain.gain.setValueAtTime(
        this._muted ? 0 : this._volume,
        this.ctx!.currentTime,
      );
    }
    this.saveSettings();
  }

  get muted() { return this._muted; }
  set muted(m: boolean) {
    this._muted = m;
    if (this.masterGain) {
      this.masterGain.gain.setValueAtTime(
        m ? 0 : this._volume,
        this.ctx!.currentTime,
      );
    }
    this.saveSettings();
  }

  private ensureCtx(): AudioContext {
    if (!this.ctx) {
      this.ctx = new AudioContext();
      this.masterGain = this.ctx.createGain();
      this.masterGain.gain.value = this._muted ? 0 : this._volume;
      this.masterGain.connect(this.ctx.destination);
      this.loadSettings();
    }
    if (this.ctx.state === 'suspended') {
      this.ctx.resume().catch(() => {});
    }
    return this.ctx;
  }

  private loadSettings() {
    try {
      const data = localStorage.getItem('neon-sprint-audio');
      if (data) {
        const s = JSON.parse(data);
        if (typeof s.volume === 'number') this._volume = s.volume;
        if (typeof s.muted === 'boolean') this._muted = s.muted;
        if (this.masterGain) {
          this.masterGain.gain.value = this._muted ? 0 : this._volume;
        }
      }
    } catch { /* ignore */ }
  }

  private saveSettings() {
    try {
      localStorage.setItem('neon-sprint-audio', JSON.stringify({
        volume: this._volume,
        muted: this._muted,
      }));
    } catch { /* ignore */ }
  }

  /** Bright ascending chime for orb collection */
  playOrbCollect(multiplier: number = 1) {
    const ctx = this.ensureCtx();
    const now = ctx.currentTime;
    const baseFreq = 600 + Math.min(multiplier, 10) * 60;

    // Two-tone chime
    for (let i = 0; i < 2; i++) {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      osc.frequency.setValueAtTime(baseFreq * (1 + i * 0.5), now);
      osc.frequency.exponentialRampToValueAtTime(baseFreq * (1.5 + i * 0.5), now + 0.08);
      gain.gain.setValueAtTime(0.15, now + i * 0.06);
      gain.gain.exponentialRampToValueAtTime(0.001, now + 0.15 + i * 0.06);
      osc.connect(gain);
      gain.connect(this.masterGain!);
      osc.start(now + i * 0.06);
      osc.stop(now + 0.2 + i * 0.06);
    }
  }

  /** Impact sound for obstacle hit */
  playHit() {
    const ctx = this.ensureCtx();
    const now = ctx.currentTime;

    // Noise burst + low thud
    const bufferSize = ctx.sampleRate * 0.15;
    const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      data[i] = (Math.random() * 2 - 1) * Math.exp(-i / (bufferSize * 0.15));
    }
    const noise = ctx.createBufferSource();
    noise.buffer = buffer;
    const noiseGain = ctx.createGain();
    noiseGain.gain.setValueAtTime(0.3, now);
    noiseGain.gain.exponentialRampToValueAtTime(0.001, now + 0.15);

    const filter = ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(800, now);
    filter.frequency.exponentialRampToValueAtTime(200, now + 0.1);

    noise.connect(filter);
    filter.connect(noiseGain);
    noiseGain.connect(this.masterGain!);
    noise.start(now);
    noise.stop(now + 0.15);

    // Low thud
    const osc = ctx.createOscillator();
    const oscGain = ctx.createGain();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(80, now);
    osc.frequency.exponentialRampToValueAtTime(30, now + 0.2);
    oscGain.gain.setValueAtTime(0.4, now);
    oscGain.gain.exponentialRampToValueAtTime(0.001, now + 0.2);
    osc.connect(oscGain);
    oscGain.connect(this.masterGain!);
    osc.start(now);
    osc.stop(now + 0.25);
  }

  /** Shield break sound */
  playShieldBreak() {
    const ctx = this.ensureCtx();
    const now = ctx.currentTime;

    // Glass-like shatter
    for (let i = 0; i < 4; i++) {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      const freq = 2000 + Math.random() * 3000;
      osc.frequency.setValueAtTime(freq, now);
      osc.frequency.exponentialRampToValueAtTime(freq * 0.3, now + 0.3);
      gain.gain.setValueAtTime(0.08, now + i * 0.02);
      gain.gain.exponentialRampToValueAtTime(0.001, now + 0.25 + i * 0.02);
      osc.connect(gain);
      gain.connect(this.masterGain!);
      osc.start(now + i * 0.02);
      osc.stop(now + 0.3 + i * 0.02);
    }
  }

  /** Power-up pickup sound */
  playPowerUp(type: string) {
    const ctx = this.ensureCtx();
    const now = ctx.currentTime;

    // Ascending arpeggio
    const baseFreqs: Record<string, number> = {
      shield: 400,
      magnet: 500,
      slow_mo: 300,
    };
    const base = baseFreqs[type] || 400;

    for (let i = 0; i < 4; i++) {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = i < 2 ? 'sine' : 'triangle';
      const freq = base * Math.pow(1.26, i); // minor third intervals
      osc.frequency.setValueAtTime(freq, now + i * 0.08);
      gain.gain.setValueAtTime(0.12, now + i * 0.08);
      gain.gain.exponentialRampToValueAtTime(0.001, now + 0.2 + i * 0.08);
      osc.connect(gain);
      gain.connect(this.masterGain!);
      osc.start(now + i * 0.08);
      osc.stop(now + 0.3 + i * 0.08);
    }
  }

  /** Countdown beep (higher pitch for GO) */
  playCountdown(value: number) {
    const ctx = this.ensureCtx();
    const now = ctx.currentTime;

    const freq = value > 0 ? 440 : 880; // GO is higher
    const duration = value > 0 ? 0.12 : 0.25;

    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'square';
    osc.frequency.setValueAtTime(freq, now);
    gain.gain.setValueAtTime(0.15, now);
    gain.gain.linearRampToValueAtTime(0.15, now + duration * 0.8);
    gain.gain.exponentialRampToValueAtTime(0.001, now + duration);
    osc.connect(gain);
    gain.connect(this.masterGain!);
    osc.start(now);
    osc.stop(now + duration + 0.01);
  }

  /** Menu button click */
  playClick() {
    const ctx = this.ensureCtx();
    const now = ctx.currentTime;

    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(1200, now);
    osc.frequency.exponentialRampToValueAtTime(800, now + 0.04);
    gain.gain.setValueAtTime(0.1, now);
    gain.gain.exponentialRampToValueAtTime(0.001, now + 0.06);
    osc.connect(gain);
    gain.connect(this.masterGain!);
    osc.start(now);
    osc.stop(now + 0.07);
  }

  /** Multiplier increase sound */
  playMultiplierUp(level: number) {
    const ctx = this.ensureCtx();
    const now = ctx.currentTime;

    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'triangle';
    const freq = 500 + level * 100;
    osc.frequency.setValueAtTime(freq, now);
    osc.frequency.exponentialRampToValueAtTime(freq * 1.5, now + 0.1);
    gain.gain.setValueAtTime(0.1, now);
    gain.gain.exponentialRampToValueAtTime(0.001, now + 0.12);
    osc.connect(gain);
    gain.connect(this.masterGain!);
    osc.start(now);
    osc.stop(now + 0.15);
  }

  /** Game over sound */
  playGameOver() {
    const ctx = this.ensureCtx();
    const now = ctx.currentTime;

    // Descending minor arpeggio
    const freqs = [660, 554, 440, 330];
    for (let i = 0; i < freqs.length; i++) {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      osc.frequency.setValueAtTime(freqs[i], now + i * 0.15);
      gain.gain.setValueAtTime(0.15, now + i * 0.15);
      gain.gain.exponentialRampToValueAtTime(0.001, now + 0.25 + i * 0.15);
      osc.connect(gain);
      gain.connect(this.masterGain!);
      osc.start(now + i * 0.15);
      osc.stop(now + 0.3 + i * 0.15);
    }
  }

  /** New record fanfare */
  playNewRecord() {
    const ctx = this.ensureCtx();
    const now = ctx.currentTime;

    // Ascending major arpeggio with harmonics
    const freqs = [523, 659, 784, 1047]; // C5 E5 G5 C6
    for (let i = 0; i < freqs.length; i++) {
      const osc = ctx.createOscillator();
      const osc2 = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      osc2.type = 'triangle';
      osc.frequency.setValueAtTime(freqs[i], now + i * 0.12);
      osc2.frequency.setValueAtTime(freqs[i] * 2, now + i * 0.12);
      gain.gain.setValueAtTime(0.12, now + i * 0.12);
      gain.gain.linearRampToValueAtTime(0.12, now + 0.15 + i * 0.12);
      gain.gain.exponentialRampToValueAtTime(0.001, now + 0.4 + i * 0.12);
      osc.connect(gain);
      osc2.connect(gain);
      gain.connect(this.masterGain!);
      osc.start(now + i * 0.12);
      osc.stop(now + 0.45 + i * 0.12);
      osc2.start(now + i * 0.12);
      osc2.stop(now + 0.45 + i * 0.12);
    }
  }

  /** Achievement unlock jingle */
  playAchievement() {
    const ctx = this.ensureCtx();
    const now = ctx.currentTime;

    const freqs = [880, 1109, 1319]; // A5 C#6 E6 major triad
    for (let i = 0; i < freqs.length; i++) {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      osc.frequency.setValueAtTime(freqs[i], now + i * 0.07);
      gain.gain.setValueAtTime(0.1, now + i * 0.07);
      gain.gain.exponentialRampToValueAtTime(0.001, now + 0.25 + i * 0.07);
      osc.connect(gain);
      gain.connect(this.masterGain!);
      osc.start(now + i * 0.07);
      osc.stop(now + 0.3 + i * 0.07);
    }
  }

  /** Lane switch whoosh */
  playLaneSwitch() {
    const ctx = this.ensureCtx();
    const now = ctx.currentTime;

    const bufferSize = ctx.sampleRate * 0.06;
    const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      data[i] = (Math.random() * 2 - 1) * Math.exp(-i / (bufferSize * 0.3));
    }
    const noise = ctx.createBufferSource();
    noise.buffer = buffer;

    const filter = ctx.createBiquadFilter();
    filter.type = 'bandpass';
    filter.frequency.setValueAtTime(3000, now);
    filter.frequency.exponentialRampToValueAtTime(1500, now + 0.05);
    filter.Q.value = 2;

    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0.08, now);
    gain.gain.exponentialRampToValueAtTime(0.001, now + 0.06);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain!);
    noise.start(now);
    noise.stop(now + 0.07);
  }
}

/** Singleton audio manager */
export const audioManager = new AudioManager();

/**
 * Lifetime Stats Tracker for Neon Sprint
 * Persists across sessions via localStorage.
 */

export interface LifetimeStats {
  totalGames: number;
  totalDistance: number;
  totalOrbs: number;
  totalScore: number;
  totalTimePlayed: number;
  totalPowerUps: number;
  longestRun: number;
  highestSpeed: number;
  longestCombo: number;
  bestMultiplier: number;
  gamesPerMode: Record<string, number>;
}

const STORAGE_KEY = 'neon-sprint-lifetime-stats';

const DEFAULT_STATS: LifetimeStats = {
  totalGames: 0,
  totalDistance: 0,
  totalOrbs: 0,
  totalScore: 0,
  totalTimePlayed: 0,
  totalPowerUps: 0,
  longestRun: 0,
  highestSpeed: 0,
  longestCombo: 0,
  bestMultiplier: 0,
  gamesPerMode: {},
};

export class StatsTracker {
  private stats: LifetimeStats;

  constructor() {
    this.stats = this.load();
  }

  private load(): LifetimeStats {
    try {
      const data = localStorage.getItem(STORAGE_KEY);
      if (data) {
        const parsed = JSON.parse(data);
        return { ...DEFAULT_STATS, ...parsed };
      }
    } catch { /* ignore */ }
    return { ...DEFAULT_STATS };
  }

  private save() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(this.stats));
    } catch { /* ignore */ }
  }

  /** Record a completed run */
  recordRun(data: {
    mode: string;
    distance: number;
    orbs: number;
    score: number;
    time: number;
    powerUps: number;
    maxSpeed: number;
    longestCombo: number;
    bestMultiplier: number;
  }) {
    this.stats.totalGames++;
    this.stats.totalDistance += data.distance;
    this.stats.totalOrbs += data.orbs;
    this.stats.totalScore += data.score;
    this.stats.totalTimePlayed += data.time;
    this.stats.totalPowerUps += data.powerUps;
    this.stats.longestRun = Math.max(this.stats.longestRun, data.distance);
    this.stats.highestSpeed = Math.max(this.stats.highestSpeed, data.maxSpeed);
    this.stats.longestCombo = Math.max(this.stats.longestCombo, data.longestCombo);
    this.stats.bestMultiplier = Math.max(this.stats.bestMultiplier, data.bestMultiplier);

    if (!this.stats.gamesPerMode[data.mode]) {
      this.stats.gamesPerMode[data.mode] = 0;
    }
    this.stats.gamesPerMode[data.mode]++;

    this.save();
  }

  get(): LifetimeStats {
    return { ...this.stats };
  }

  reset() {
    this.stats = { ...DEFAULT_STATS };
    this.save();
  }

  /** Format distance for display */
  static formatDistance(d: number): string {
    if (d >= 1000) return `${(d / 1000).toFixed(1)}km`;
    return `${Math.floor(d)}m`;
  }

  /** Format time for display */
  static formatTime(seconds: number): string {
    if (seconds >= 3600) {
      const h = Math.floor(seconds / 3600);
      const m = Math.floor((seconds % 3600) / 60);
      return `${h}h ${m}m`;
    }
    const m = Math.floor(seconds / 60);
    const s = Math.floor(seconds % 60);
    return `${m}m ${s}s`;
  }
}

